void solve(int CASE)
{
	int n; cin >> n;
	var s = vector<int>(n + 2);
	var siz = vector<int>(n + 2, 1);
	fa(i, 1, n + 1)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return s[x];
		return s[x] = find(find, s[x]);
		};
	var vis = vector<int>(n + 2); // 是否在最右链上
	var to = vector<int>(n + 2);  // i 在最右链上，to[i] 是 i 在最右链上的子节点
	var g = vector<vector<int>>(n + 2);
	vis[1] = 1;

	int ans = 0;
	fa(i, 2, n + 1) {
		int f; cin >> f;
		if (vis[f]) {
			// f 在最右链上
			// 处理 f 的子树中，原来也在最右链上的
			var it = to[f];
			if (it) {
				var dfs = [&](var dfs, int now, int fa)->void {
					vis[now] = 0;
					int e1 = find(find, now);
					for (int to : g[now]) {
						int e2 = find(find, to);
						s[e2] = e1;
						siz[e1] += siz[e2];
						if (vis[to])dfs(dfs, to, now);
					}
					};
				dfs(dfs, it, 0);
				ans = max(ans, siz[it]);
			}
			to[f] = i;
			vis[i] = 1;
		}
		else {
			int e1 = find(find, f);
			int e2 = find(find, i);
			s[e2] = e1;
			siz[e1] += siz[e2];
			ans = max(ans, siz[e1]);
		}
		g[f].pb(i);
		cout << ans << endl;
	}
	return;
}
